#include <iostream>

class DynString {
    char* m_data{};
    int m_length{};
public:
    DynString() = default;
    ~DynString() { delete[] m_data; }
    DynString(const char* str) {
        m_length = 0;
        while (str[m_length] != '\0') ++m_length;
        m_data = new char[m_length + 1];
        for (int i{ 0 }; i <= m_length; ++i) m_data[i] = str[i];
    }
    DynString(const DynString& src) : m_length{ src.m_length } {
        if (src.m_data) {
            m_data = new char[m_length + 1];
            for (int i{ 0 }; i <= m_length; ++i) m_data[i] = src.m_data[i];
        }
    }
    DynString& operator=(const DynString& src) {
        if (this != &src) {
            delete[] m_data;
            m_data = nullptr;
            m_length = src.m_length;
            if (src.m_data) {
                m_data = new char[m_length + 1];
                for (int i{ 0 }; i <= m_length; ++i) m_data[i] = src.m_data[i];
            }
        }
        return *this;
    }
    DynString(DynString&& src) noexcept
        : m_data{ src.m_data }, m_length{ src.m_length } {
        src.m_data = nullptr; src.m_length = 0;
    }
    DynString& operator=(DynString&& src) noexcept {
        if (this != &src) {
            delete[] m_data;
            m_data = src.m_data; m_length = src.m_length;
            src.m_data = nullptr; src.m_length = 0;
        }
        return *this;
    }
    void print() const {
        std::cout << (m_data ? m_data : "empty") << '\n';
    }
};

DynString makeGreeting(const char* str) {
    DynString ds{ str };
    return ds;
}

