    char word[101]{};
    std::cin >> word;
    DynString a{ word };
    a.print();
    DynString b{ a };
    b.print();
    DynString c{};
    c = a; // copy assignment
    c.print();
    DynString d{ makeGreeting(word) }; // constructed directly via copy elision (C++17)
    d.print();
    DynString e{};
    e = DynString{}; // move assignment with empty
    e.print();
    return 0;
