        auto b = std::make_shared<BadNode>(idB);
        a->next = b;
        b->next = a;
        std::cout << "Circular: A count = " << a.use_count()
                  << ", B count = " << b.use_count() << "\n";
        a.reset();
        b.reset();
        std::cout << "Circular after reset: A count = "
                  << a.use_count() << ", B count = " << b.use_count() << "\n";
    }

    // Part 2: Fixed with weak_ptr
    {
        auto a2 = std::make_shared<GoodNode>(idA);
        auto b2 = std::make_shared<GoodNode>(idB);
        a2->next = b2;
        b2->next = a2;
        std::cout << "Fixed: A count = " << a2.use_count()
                  << ", B count = " << b2.use_count() << "\n";

        std::weak_ptr<GoodNode> obs = a2->next;
        std::cout << std::boolalpha;
        std::cout << "A expired: " << obs.expired() << "\n";
        b2.reset();
        std::cout << "A expired: " << obs.expired() << "\n";
    }

