    std::cout << "lock released, refs: " << original.use_count() << '\n';

    copy.reset();
    std::cout << "copy reset, refs: " << original.use_count() << '\n';

    original.reset();
    std::cout << "original reset, refs: " << original.use_count() << '\n';

    std::cout << "weak expired: " << (weak.expired() ? "true" : "false") << '\n';

